25	export class BayesApiError extends Error {
26	  constructor(
27	    public status: number,
28	    public code: string,
29	    public details: Record<string, unknown> = {},
30	  ) {
31	    super(`${code}: ${status}`);
32	    this.name = "BayesApiError";
33	  }
